import type { FunctionComponent, ReactElement } from 'react';
import type { I18nBaseProps, PrimitiveType } from './common';

import { captureOwnerStack, createElement, Fragment } from 'react';

import { createDeprecationLogger } from '@meli/deprecation';

const logDeprecated = /* #__PURE__*/ createDeprecationLogger('@nordic/i18n');

const COMPONENT_REPLACEMENT_REGEX = /(?:\{(\d+)\}(.+?)\{\1\}|\{(\d+)\})/g;
const REPLACEMENT_REGEX = /\{(\d+)\}/g;

type I18nReplacementComponents =
  | (() => ReactElement)
  | ((text: string) => ReactElement);

type Replacements = Array<PrimitiveType> | Record<number, PrimitiveType>;

export type I18nWithComponentsProps = I18nBaseProps & {
  /**
   * Replace placeholders with custom React components.
   *
   * @deprecated Use `values` prop instead.
   * @see {@link https://nordic.adminml.com/docs/migration-guides/modules/i18n/tags-and-components-to-values | Migration Guide}
   */
  components: Record<number, I18nReplacementComponents>;

  /**
   * Replace placeholders with given values.
   *
   * @deprecated Use `values` prop instead.
   * @see {@link https://nordic.adminml.com/docs/migration-guides/modules/i18n/tags-and-components-to-values | Migration Guide}
   */
  replacements?: Replacements;
};

const processNestedReplacement = (
  text: string,
  replacements?: Replacements,
) => {
  if (!replacements) {
    return text;
  }

  return text.replace(REPLACEMENT_REGEX, (match, index) => {
    const replacementValue = replacements[+index];

    return replacementValue ? `${replacementValue}` : match;
  });
};

// TODO: Remove in next breaking
export const I18nWithComponents: FunctionComponent<I18nWithComponentsProps> = (
  props,
) => {
  if (__DEV__) {
    const stack = captureOwnerStack()!.split('\n');

    stack.shift();
    logDeprecated(
      '"components" prop is deprecated. Use "values" prop instead. Refer to the migration guide: https://nordic.adminml.com/docs/migration-guides/modules/i18n/tags-and-components-to-values',
      { customStack: stack },
    );
  }

  const { wrapper, text, components, className, replacements } = props;
  const children: Array<ReactElement | string> = [];
  const matches = text.matchAll(COMPONENT_REPLACEMENT_REGEX);

  let textIndex = 0;

  for (const match of matches) {
    const [matchedText, pairIndex, pairParam, singleIndex] = match;

    children.push(text.substring(textIndex, match.index));
    textIndex = match.index + matchedText.length;

    if (pairIndex) {
      const component = components[+pairIndex];

      children.push(
        component ? (
          <Fragment key={`${pairIndex}_${pairParam!}`}>
            {component(processNestedReplacement(pairParam!, replacements))}
          </Fragment>
        ) : (
          matchedText
        ),
      );
    } else {
      const replacementIndex = +singleIndex!;

      if (components[replacementIndex]) {
        const component = components[replacementIndex] as () => ReactElement;

        children.push(
          <Fragment key={`${matchedText}_${match.index}`}>
            {component()}
          </Fragment>,
        );
      } else if (replacements?.[replacementIndex]) {
        children.push(`${replacements[replacementIndex]}`);
      } else {
        children.push(matchedText);
      }
    }
  }

  const trailingText = text.substring(textIndex);

  if (trailingText) {
    children.push(trailingText);
  }

  if (wrapper) {
    return createElement(wrapper, { className }, children);
  }

  return children;
};
